module top_module(
    input [3:0] obf_a,
    input [3:0] b,
    input sel,
    output reg [3:0] out
);always @(*) begin
        out[0] = obf_a[0] ^ (sel & b[0]);
        out[1] = obf_a[1] ^ (sel & b[1]);
        out[2] = obf_a[2] ^ (sel & b[2]);
        out[3] = obf_a[3] ^ (sel & b[3]);
    end

endmodule
